#include<bits/stdc++.h>
#define int long long
using namespace std;
int n,q,a[1000005],t,maxx,sum,minn=1e9;
int find(int x) {
	int l=0,r=n+1;
	while(l+1!=r) {
		int mid=(l+r)/2;
		if(a[mid]<x)
			r=mid;
		else
			l=mid;
	}
	return l;
}
bool cmp(int x,int y) {
	return x>y;
}
signed main() {
	ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
	cin>>n>>q;
	n=n*n;
	for(int i=1; i<=n; i++) {
		cin>>a[i];
	}
	sort(a+1,a+n+1,cmp);
	for(int i=1; i<=n; i++) {
		minn=min(minn,a[i]);
	}
	while(q--) {
		cin>>t;
		if(t<minn) {
			cout<<sqrt(n)<<"\n";
		} else {
			int t1=sqrt(n);
			cout<<min(t1,find(t))<<"\n";
		}
	}
	return 0;
}
